    public ProfileRepository(JdbcTemplate jdbc) {
        this.jdbc = jdbc;
    }

    public void updateDisplayName(long userId, String displayName) {
        jdbc.update("UPDATE profile SET display_name = ? WHERE id = ?", displayName, userId);
    }
}

